  end

  def handle_call({:deposit, account_number, amount}, _from, state) do
    case :ets.lookup(@ets_table, account_number) do
      [{account_number, balance}] ->
        new_balance = balance + amount
        :ets.insert(@ets_table, {account_number, new_balance})
